import CardCarrito from "../tarjeta-carrito/card-carrito";
import "./carrito.css"

function Carrito() {

    


    return (
        <ul className="cont-carrito">
            
            <div className="btns-contenedor">
                <button className="btns-cont-vaciar" type="submit">Vaciar Carrito</button>
                <h4>Precio total: $</h4>
                <button className="btns-cont-pagar" type="submit">Ir a Pagar</button>
            </div>

        </ul>
    )
}

export default Carrito;
